import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider } from './context/CartContext';

// Importación de componentes
import Header from './components/Header';
import Login from './components/Login';
import VistaCliente from './components/VistaCliente'; // Panel con filtros y categorías
import DashboardVendedor from './components/DashboardVendedor'; // Tu carga predictiva
import Registro from './components/Registro';

// Componente para proteger rutas
const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();

    if (loading) return (
        <div style={{ display: 'flex', justifyContent: 'center', marginTop: '50px', fontFamily: 'sans-serif' }}>
            <div style={{ textAlign: 'center' }}>
                <p>Cargando sesión...</p>
            </div>
        </div>
    );

    if (!isAuthenticated) return <Navigate to="/login" />;

    if (roleRequired && user?.rol !== roleRequired) {
        return <Navigate to="/" />;
    }

    return children;
};

const AppRoutes = () => {
    const { user, isAuthenticated } = useAuth();

    return (
        <>
            {/* El Header aparece en toda la aplicación */}
            <Header /> 

            <Routes>
                {/* --- RUTAS PÚBLICAS --- */}
                <Route 
                    path="/login" 
                    element={!isAuthenticated ? <Login /> : <Navigate to="/" />} 
                />
                <Route path="/registro" element={<Registro />} />

                {/* --- RUTA RAÍZ (Home Inteligente) --- */}
                <Route path="/" element={
                    <PrivateRoute>
                        {user?.rol === 'vendedor' ? <DashboardVendedor /> : <VistaCliente />}
                    </PrivateRoute>
                } />

                {/* --- RUTA DASHBOARD VENDEDOR (Carga de Productos) --- */}
                <Route path="/dashboard" element={
                    <PrivateRoute roleRequired="vendedor">
                        <DashboardVendedor />
                    </PrivateRoute>
                } />

                {/* --- RUTA PANEL CLIENTE (Supermercado / Filtros) --- */}
                <Route path="/panel-cliente" element={
                    <PrivateRoute roleRequired="cliente">
                        <VistaCliente />
                    </PrivateRoute>
                } />

                {/* --- REDIRECCIÓN POR DEFECTO --- */}
                <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </>
    );
};

function App() {
    return (
        <AuthProvider>
            <CartProvider>
                <Router>
                    <div style={{ minHeight: '100vh', background: '#f8fafc' }}>
                        <AppRoutes />
                    </div>
                </Router>
            </CartProvider>
        </AuthProvider>
    );
}

export default App;
